```csharp
private void ApplyHover()
{
    if (hoverPoints == null)
        return;

    foreach (GameObject hoverPoint in hoverPoints)
    {
        RaycastHit hit;
        if (Physics.Raycast(hoverPoint.transform.position, -Vector3.up, out hit, hoverHeight))
        {
            float proportionalHeight = (hoverHeight - hit.distance) / hoverHeight;
            Vector3 appliedHoverForce = Vector3.up * hoverForce * proportionalHeight;
            appliedHoverForce = appliedHoverForce * Time.deltaTime * rb.mass;
            rb.AddForceAtPosition(appliedHoverForce, hoverPoint.transform.position);
